    // Why SWAM Section
    "whySwam.title": "لماذا تختار",
    "whySwam.swam": "سوام؟",
    "whySwam.subtitle":
      "أربعة عقود من التميز الهندسي والابتكار والالتزام الثابت بالجودة.",
    "whySwam.excellence.title": "أربعة عقود من التميز",
    "whySwam.excellence.description":
      "منذ عام 1978، كانت سوام في طليعة التميز الهندسي، حيث قدمت مضخات التفريغ والمنافيخ والضواغط عالية الأداء للصناعات في جميع أنحاء العالم. مع أكثر من أربعة عقود من الخبرة المثبتة، نحن نمثل الموثوقية والابتكار والثقة.",
    "whySwam.quality.title": "الجودة والابتكار",
    "whySwam.quality.description":
      'نتبع شعار "افعلها مرة واحدة وافعلها بشكل صحيح". تركيزنا على المنتجات عالية الجودة والموثوقة والمتينة التي تلبي أو تتجاوز المعايير الدولية. تخضع جميع المنتجات لاختبار "التشغيل الساخن" الداخلي، مع شهادات اختبار الأداء كجزء من ممارساتنا القياسية.',
    "whySwam.manufacturing.title": "التصنيع المتقدم",
    "whySwam.manufacturing.description":
      "تستخدم سوام عمليات هندسية حديثة مع مصانع تصنيع متعددة مجهزة بآلات CNC. نطور منتجات موفرة للطاقة، مثل منافيخ اللولب، التي يمكن أن توفر أكثر من 25٪ في الطاقة مقارنة بالمنافيخ التقليدية.",
    "whySwam.standards.title": "معايير الاختبار والشهادات",
    "whySwam.standards.description":
      "تم تصميم واختبار جميع المنتجات وفقًا للمعايير الدولية مثل BS-1571 و Pneurop و HEI و API-681 و API-619 إلخ. سوام هي منظمة معتمدة من ISO-9001 مع محفظة منتجات رئيسية معتمدة بشهادات خطرة مثل CE و ATEX وغيرها.",
    "whySwam.engineering.title": "التميز الهندسي",
    "whySwam.engineering.description":
      "تصنيع CNC متقدم، اختبار تشغيل ساخن داخلي حتى 1000 كيلو وات، والتحقق من الأداء المعتمد. تصميمات الجيل القادم، بما في ذلك منافيخ اللولب التي تقلل من استخدام الطاقة بنسبة 25٪ أو أكثر.",
    "whySwam.global.title": "الحضور العالمي والشراكة",
    "whySwam.global.description":
      'نخدم أكثر من 15 دولة مع مكاتب عالمية في أستراليا ودبي والولايات المتحدة. حلول مخصصة وأنظمة تسليم مفتاح مصممة لتلبية أصعب التحديات الصناعية. في سوام، شعارنا "افعلها مرة واحدة، وافعلها بشكل صحيح" يحدد كل حل نقدمه - مما يجعلنا شريكًا عالميًا موثوقًا للصناعات من الكيماويات والبتروكيماويات إلى الطاقة ومعالجة المياه.',
    "whySwam.discoverMore": "اكتشف المزيد",
    "whySwam.showLess": "عرض أقل",

    // Core Values
    "coreValues.title": "ما يدفعنا للأمام",
    "coreValues.subtitle":
      "هذه المبادئ الأساسية توجه كل قرار نتخذه وكل حل نقدمه.",
    "coreValues.innovation.title": "الابتكار",
    "coreValues.innovation.description":
      "الابتكار أكثر من مجرد فكرة - إنه عقلية. دافع لا يتوقف للتفكير بشكل مختلف، لكسر الحدود، وخلق ما هو قادم.",
    "coreValues.technology.title": "التكنولوجيا",
    "coreValues.technology.description":
      "التكنولوجيا هي الجسر بين الخيال والواقع. إنها تدفع التقدم، وتربط العالم، وتحول كيف نعيش ونعمل.",
    "coreValues.excellence.title": "التميز",
    "coreValues.excellence.description":
      "التميز ليس وجهة. إنه التزام - ينعكس في كل تفصيل، كل قرار، كل نتيجة.",
    "coreValues.sustainability.title": "الاستدامة",
    "coreValues.sustainability.description":
      "الاستدامة هي وعدنا للمستقبل. للابتكار بمسؤولية. للنمو بهدف. لترك عالم أفضل مما وجدناه.",

