    // History Page
    "history.hero.title": "Наш",
    "history.hero.titleHighlight": "Путь",
    "history.hero.description":
      "От скромных начал в 1978 году до становления мировым лидером в области пневматических решений",
    "history.hero.yearsOfInnovation": "45+ лет инноваций",
    "history.timelineSection.title": "Наша",
    "history.timelineSection.titleHighlight": "История",
    "history.timelineSection.description":
      "Десятилетия инноваций, роста и совершенства в пневматических решениях",
    "history.timeline.1978.title": "ОТКРЫТИЕ",
    "history.timeline.1978.description":
      "Основание компании Swam Pneumatics Pvt. Ltd г-ном С.К. Гамбхиром.",
    "history.timeline.1982.title": "КОРПОРАТИВНЫЕ ОФИСЫ",
    "history.timeline.1982.description": "Корпоративные офисы созданы в Нойде.",
    "history.timeline.1996.title": "Рост компании",
    "history.timeline.1996.description":
      "Рост компании после присоединения г-на Абхишека Гамбхира.",
    "history.timeline.2000.title": "Производство",
    "history.timeline.2000.description":
      "Введение стандартов ISO – Производство.",
    "history.timeline.2002.title": "Учреждено",
    "history.timeline.2002.description": "Второй завод создан в Нойде",
    "history.timeline.2003.title": "Мощность",
    "history.timeline.2003.description":
      "Swam производил крупные вентиляторы мощностью 30 000, и производственная мощность была расширена на существующих заводах.",
    "history.timeline.2004.title": "Производство",
    "history.timeline.2004.description":
      "Вакуумные усилители в сочетании с обычными механическими вакуумными насосами повышают высокий вакуум до одного микрона. Идеально подходит для низкой стоимости, высокого смещения и вакуума от 50 Торр до одного микрона.",
    "history.timeline.2005.title": "OHSAS",
    "history.timeline.2005.description": "Введение стандартов ISO – OHSAS",
    "history.timeline.2006.title": "ЧПУ",
    "history.timeline.2006.description":
      "Модернизация заводов до станков с ЧПУ",
    "history.timeline.2009.title": "ВЕНТИЛЯТОР ГРУЗОВИКА",
    "history.timeline.2009.description":
      "Введение продукции вентиляторов. Вентилятор грузовика: Вентиляторы Swam для навалочных грузовиков специально разработаны для удовлетворения операционных требований навалочных и силосных транспортных средств в генерации давления и вакуума, необходимых для пневматической загрузки и разгрузки.",
    "history.timeline.2010.title": "НАСОСЫ",
    "history.timeline.2010.description":
      "Начало производства вакуумных насосов с жидкостным кольцом. • Мощность 36000 М3 / Час. • Вакуум до 90%. • Давление до 1,1 бар'г' в одной ступени. • Подходит для положительной и отрицательной транспортировки и усиления.",
    "history.timeline.2012.title": "УЧРЕЖДЕНО",
    "history.timeline.2012.description":
      "Начало сухих винтовых вакуумных насосов. 3-й завод создан в Нойде.",
    "history.timeline.2014.title": "УЧРЕЖДЕНО",
    "history.timeline.2014.description": "Создан Swam Middle East FZE Дубай",
    "history.timeline.2015.title": "УЧРЕЖДЕНО",
    "history.timeline.2015.description":
      "• 4-й завод создан в Нойде. • Создан Swam International Pvt. Ltd. (Австралия).",
    "history.timeline.2016.title": "ТУРБО ВЕНТИЛЯТОР, ВИНТОВОЙ ВЕНТИЛЯТОР",
    "history.timeline.2016.description":
      "Введение продукции вентиляторов. Турбо вентилятор: Высокоэффективные турбо вентиляторы Swam - это самая продвинутая одноступенчатая центробежная машина на основе высокоскоростной специализированной технологии без масла. Винтовой вентилятор: Самый продвинутый энергоэффективный вентилятор с экономией более 25% потребления энергии по сравнению с обычными вентиляторами. Доступен в широких размерах до 9000 м3 / час.",
    "history.growthPhilosophy.title": "Наша",
    "history.growthPhilosophy.titleHighlight": "Философия Роста",
    "history.growthPhilosophy.description":
      "SWAM продолжает расти из года в год. Наш фокус и история - это рост через наши основные принципы, которые определяют, кто мы есть, и направляют все, что мы делаем.",
